UPDATE recipes SET instructions = '["Slice the Shallot, Fennel, and Red Chilli, then cook gently in the Coconut Oil until softened","Add the Ginger, Garlic, Cumin Seeds, Bay Leaf, and Cinnamon Stick.","Season to taste","Stir in the Turmeric, soaked Yellow Peas, Maple Syrup, and Chicken Stock","Bring to a gentle simmer, cover, and cook for about 1 hour, until the peas are tender and creamy","Stir through the Cavolo Nero and Lime Juice just before serving, adjusting seasoning to taste","For the Tarka","Heat the Coconut Oil in a small pan","Then add the Garlic, Red Chilli, Curry Leaves, and, after a minute or two, the Nigella Seeds","Cook until aromatic and lightly crisp","To Serve","Spoon the Dhal into 2 bowls, drizzle with the hot Tarka, and top with Coconut Yoghurt, Coriander and Lime wedges.","To Serve","125g Coconut Yoghurt","Coriander","Lime Wedges"]'::jsonb WHERE title ILIKE '%Split Yellow Pea Dhal%';